{
  "name": "Super-Mentor AI: The AI Curator Analysis",
  "description": "A high-performance analysis tool for product strategy, fusing Cagan, Blue Ocean, and YC mental models to identify market gaps.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Competitor {
  name: string;
  traffic: string;
  promise: string;
}

export interface AnalysisResult {
  snapshot: Competitor[];
  friction: string[];
  errc: {
    eliminate: string[];
    reduce: string[];
    raise: string[];
    create: string[];
  };
  features: {
    title: string;
    description: string;
  }[];
  groundingUrls: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMarketAnalysis = async (ideaDescription: string): Promise<AnalysisResult> => {
  const prompt = `
    פעל כ"סופר-מנטור" המשלב את Marty Cagan, W. Chan Kim ו-Paul Graham.
    נתח את הרעיון: "${ideaDescription}"

    עליך לבצע מחקר שוק בזמן אמת באמצעות Google Search כדי למצוא את 3-5 המתחרים המובילים (Market Leaders) בתחום של אגרגטורים לחדשות וכלי AI.

    פעל בדיוק לפי המבנה הבא והחזר תוצאה בפורמט JSON:
    1. Market Snapshot: רשימת מתחרים, הערכת תנועה חודשית וההבטחה המרכזית שלהם.
    2. Friction Analysis: רשימת נקודות חיכוך של משתמשים ומה שחסר בשוק.
    3. ERRC Strategy Grid: 
       - Eliminate (מה להסיר)
       - Reduce (מה לצמצם)
       - Raise (מה להעלות ברמה)
       - Create (מה ליצור כחדשנות ערך)
    4. The Killer Features: 3 תכונות ספציפיות שפותרות את החיכוך.

    כללים קריטיים:
    - שפה: עברית.
    - בטיחות RTL: מונחים באנגלית צריכים להיות בשורה נפרדת או בסוגריים.
    - ללא הקדמות או סיכומים (No fluff).
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          snapshot: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                traffic: { type: Type.STRING },
                promise: { type: Type.STRING }
              }
            }
          },
          friction: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          errc: {
            type: Type.OBJECT,
            properties: {
              eliminate: { type: Type.ARRAY, items: { type: Type.STRING } },
              reduce: { type: Type.ARRAY, items: { type: Type.STRING } },
              raise: { type: Type.ARRAY, items: { type: Type.STRING } },
              create: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          },
          features: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                description: { type: Type.STRING }
              }
            }
          }
        },
        required: ["snapshot", "friction", "errc", "features"]
      }
    }
  });

  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const urls = groundingChunks
    .map((chunk: any) => chunk.web?.uri)
    .filter((uri: string | undefined): uri is string => !!uri);

  return {
    ...JSON.parse(response.text),
    groundingUrls: Array.from(new Set(urls))
  };
};

import React, { useState, useEffect } from 'react';
import { getMarketAnalysis } from './services/geminiService';
import { AnalysisResult } from './types';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const ideaDescription = `
    The AI Curator:
    Founder leverages 630k YouTube subs experience in curation.
    Mechanism: Automated scanning + Human filter (Top 1% only).
    Output: Summaries with strict source credits.
    Model: Premium Affiliate Marketing of high-quality tools only.
  `;

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const result = await getMarketAnalysis(ideaDescription);
        setData(result);
