        console.error(err);
        setError("שגיאה בניתוח הנתונים. אנא נסה שנית מאוחר יותר.");
      } finally {
        setLoading(false);
      }
    };

    fetchData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (loading) {
    return (
