    return (
      <div className="flex items-center justify-center min-h-screen bg-[#0a0a0a] text-red-500 p-6">
        <div className="bg-red-900/20 border border-red-500/50 p-8 rounded-xl max-w-lg w-full text-center">
          <h2 className="text-xl font-bold mb-4">אופס! משהו השתבש</h2>
          <p>{error}</p>
          <button 
            onClick={() => window.location.reload()} 
            className="mt-6 px-6 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition"
          >
            נסה שוב
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto p-6 pb-20 space-y-12">
      {/* Header */}
      <header className="border-b border-gray-800 pb-8 mt-8">
        <h1 className="text-4xl md:text-5xl font-black bg-gradient-to-l from-blue-400 to-emerald-400 bg-clip-text text-transparent mb-4">
          Super-Mentor AI Analysis
        </h1>
        <div className="flex flex-wrap gap-3">
          <span className="px-3 py-1 bg-gray-900 border border-gray-700 rounded-full text-xs font-mono text-gray-400 uppercase">Marty Cagan</span>
          <span className="px-3 py-1 bg-gray-900 border border-gray-700 rounded-full text-xs font-mono text-gray-400 uppercase">Blue Ocean</span>
          <span className="px-3 py-1 bg-gray-900 border border-gray-700 rounded-full text-xs font-mono text-gray-400 uppercase">Paul Graham</span>
        </div>
      </header>

      {/* Market Snapshot */}
      <section>
        <div className="flex items-center gap-3 mb-6">
          <div className="w-8 h-8 bg-blue-600 rounded flex items-center justify-center font-bold">1</div>
          <h2 className="text-2xl font-bold">Market Snapshot</h2>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {data?.snapshot.map((comp, idx) => (
            <div key={idx} className="bg-gray-900/50 border border-gray-800 p-5 rounded-xl hover:border-blue-500/50 transition group">
              <h3 className="text-xl font-bold text-white mb-2 group-hover:text-blue-400 transition">{comp.name}</h3>
              <div className="text-sm text-emerald-400 font-mono mb-3">{comp.traffic} monthly traffic</div>
              <p className="text-gray-400 text-sm leading-relaxed">{comp.promise}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Friction Analysis */}
      <section>
        <div className="flex items-center gap-3 mb-6">
          <div className="w-8 h-8 bg-orange-600 rounded flex items-center justify-center font-bold">2</div>
          <h2 className="text-2xl font-bold">The Friction Analysis</h2>
        </div>
        <div className="bg-orange-900/10 border border-orange-900/30 rounded-2xl p-6 md:p-8">
          <ul className="space-y-4">
            {data?.friction.map((point, idx) => (
              <li key={idx} className="flex items-start gap-4">
                <span className="text-orange-500 text-xl mt-1">•</span>
                <p className="text-gray-300 text-lg">{point}</p>
              </li>
            ))}
          </ul>
        </div>
      </section>

      {/* ERRC Grid */}
      <section>
        <div className="flex items-center gap-3 mb-6">
          <div className="w-8 h-8 bg-emerald-600 rounded flex items-center justify-center font-bold">3</div>
          <h2 className="text-2xl font-bold">ERRC Strategy Grid</h2>
        </div>
        <div className="overflow-hidden border border-gray-800 rounded-2xl">
          <table className="w-full border-collapse">
