                <th className="p-4 text-right border-b border-gray-800 text-gray-400 font-bold uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody>
              <tr className="hover:bg-gray-900/20 transition">
                <td className="p-4 border-b border-gray-800 font-bold text-red-400 bg-red-400/5">Eliminate</td>
                <td className="p-4 border-b border-gray-800 text-gray-300">
