                </td>
              </tr>
              <tr className="hover:bg-gray-900/20 transition">
                <td className="p-4 border-b border-gray-800 font-bold text-yellow-400 bg-yellow-400/5">Reduce</td>
                <td className="p-4 border-b border-gray-800 text-gray-300">
                  <ul className="list-disc list-inside space-y-1">
                    {data?.errc.reduce.map((item, i) => <li key={i}>{item}</li>)}
                  </ul>
                </td>
              </tr>
              <tr className="hover:bg-gray-900/20 transition">
                <td className="p-4 border-b border-gray-800 font-bold text-blue-400 bg-blue-400/5">Raise</td>
                <td className="p-4 border-b border-gray-800 text-gray-300">
                  <ul className="list-disc list-inside space-y-1">
                    {data?.errc.raise.map((item, i) => <li key={i}>{item}</li>)}
                  </ul>
                </td>
              </tr>
              <tr className="hover:bg-gray-900/20 transition">
                <td className="p-4 border-b border-gray-800 font-bold text-emerald-400 bg-emerald-400/5">Create</td>
                <td className="p-4 border-b border-gray-800 text-gray-300">
                  <ul className="list-disc list-inside space-y-1">
                    {data?.errc.create.map((item, i) => <li key={i}>{item}</li>)}
                  </ul>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </section>

      {/* Killer Features */}
      <section>
        <div className="flex items-center gap-3 mb-6">
          <div className="w-8 h-8 bg-purple-600 rounded flex items-center justify-center font-bold">4</div>
          <h2 className="text-2xl font-bold">The Killer Features</h2>
        </div>
        <div className="space-y-6">
          {data?.features.map((feature, idx) => (
            <div key={idx} className="relative group">
              <div className="absolute -inset-1 bg-gradient-to-r from-purple-600 to-blue-600 rounded-2xl blur opacity-25 group-hover:opacity-50 transition duration-1000"></div>
              <div className="relative bg-gray-900 border border-gray-800 p-6 rounded-2xl">
                <h3 className="text-xl font-bold text-white mb-3">{feature.title}</h3>
                <p className="text-gray-400 leading-relaxed">{feature.description}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Sources / Grounding */}
      {data?.groundingUrls && data.groundingUrls.length > 0 && (
        <section className="pt-12 border-t border-gray-800">
          <h3 className="text-sm font-mono text-gray-500 mb-4 uppercase tracking-widest">Sources & Research Data</h3>
          <div className="flex flex-wrap gap-4">
            {data.groundingUrls.map((url, i) => (
              <a 
                key={i} 
                href={url} 
                target="_blank" 
                rel="noopener noreferrer"
                className="text-xs text-blue-400 hover:text-blue-300 transition underline underline-offset-4 decoration-blue-400/30"
              >
                {new URL(url).hostname}
              </a>
            ))}
          </div>
        </section>
      )}

      {/* Sticky Bottom Actions */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-xs md:max-w-md px-6 z-50">
        <div className="bg-white/10 backdrop-blur-md border border-white/20 p-2 rounded-full flex gap-2 shadow-2xl">
          <button 
            onClick={() => window.print()}
            className="flex-1 py-3 px-4 bg-white text-black font-bold rounded-full hover:bg-gray-200 transition text-sm flex items-center justify-center gap-2"
          >
            <span>📄</span> הורד דו"ח
          </button>
          <button 
            onClick={() => window.location.reload()}
            className="flex-1 py-3 px-4 bg-blue-600 text-white font-bold rounded-full hover:bg-blue-700 transition text-sm flex items-center justify-center gap-2"
          >
            <span>🔄</span> ניתוח מחדש
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMarketAnalysis = async (ideaDescription: string): Promise<AnalysisResult> => {
  const prompt = `
    נתח את רעיון המוצר הבא כ"סופר-מנטור" (שילוב של Marty Cagan, W. Chan Kim, Paul Graham):
    "${ideaDescription}"

    דרישות מחקר (השתמש ב-Google Search):
    1. מצא בדיוק את 3 המתחרים המובילים ביותר (Market Leaders) בתחום אגרגטורים של חדשות/כלי AI.
    2. זהה חוסרים ספציפיים בשוק (Friction).

    החזר תוצאה בפורמט JSON בלבד. 
    היה תמציתי מאוד. כל תיאור חייב להיות עד 20 מילים.

    מבנה ה-JSON הנדרש:
    - snapshot: רשימה של 3 מתחרים (שם, תנועה מוערכת, הבטחה).
    - friction: רשימה של 5 נקודות חיכוך.
    - errc: אובייקט עם המפתחות eliminate, reduce, raise, create (רשימות מחרוזות).
    - features: 3 תכונות מנצחות (כותרת ותיאור קצר).

    כללים קריטיים:
    - שפה: עברית.
    - מונחים באנגלית בסוגריים בלבד.
    - ללא הקדמות, ללא סיכומים, ללא טקסט מחוץ ל-JSON.
    - אל תחזור על עצמך.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            snapshot: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  traffic: { type: Type.STRING },
                  promise: { type: Type.STRING }
                },
                required: ["name", "traffic", "promise"]
              }
            },
            friction: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            errc: {
              type: Type.OBJECT,
              properties: {
                eliminate: { type: Type.ARRAY, items: { type: Type.STRING } },
                reduce: { type: Type.ARRAY, items: { type: Type.STRING } },
                raise: { type: Type.ARRAY, items: { type: Type.STRING } },
                create: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["eliminate", "reduce", "raise", "create"]
            },
            features: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["title", "description"]
              }
            }
          },
          required: ["snapshot", "friction", "errc", "features"]
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("Empty response from AI");
    }

    let parsedData: any;
    try {
      parsedData = JSON.parse(text);
    } catch (parseError) {
      console.error("JSON Parse Error. Raw text:", text);
      // Attempt to fix common truncation issues if possible, though strict prompts are better
      throw new Error("התגובה מה-AI לא הייתה בפורמט תקין. אנא נסה שנית.");
    }

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const urls = groundingChunks
      .map((chunk: any) => chunk.web?.uri)
      .filter((uri: string | undefined): uri is string => !!uri);

    return {
      ...parsedData,
      groundingUrls: Array.from(new Set(urls))
    };
  } catch (error) {
    console.error("Market analysis failed:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { getMarketAnalysis } from './services/geminiService';
import { AnalysisResult } from './types';

