כמובן. כארכיטקט פתרונות ו-Senior Developer, אני מגיש לך את התשתית המלאה לבניית ה-**Curation Dashboard** מבוסס **Google Apps Script (GAS)** ו-**Gemini API**.

המערכת תסרוק את ה-Gmail שלך, תנתח את הכלים באמצעות בינה מלאכותית, ותציג ממשק ניהול מהיר לקבלת החלטות "סקייל של Paul Graham".

### שלב 1: הקוד ל-`Code.gs`
קוד זה מטפל בלוגיקה של השרת: שליפת מיילים, קריאה ל-Gemini, ושמירת נתונים.

```javascript
/**
 * קונפיגורציה בסיסית
 */
const GEMINI_API_KEY = "YOUR_GEMINI_API_KEY_HERE"; // מומלץ להשתמש ב-Script Properties
const SEARCH_QUERY = 'from:googlealerts-noreply@google.com after:2026/01/20';

function doGet() {
  return HtmlService.createTemplateFromFile('Index')
    .evaluate()
    .setTitle('AI Curator Dashboard')
    .addMetaTag('viewport', 'width=device-width, initial-scale=1')
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL);
}

/**
 * שליפת התראות וניתוחן
 */
function fetchAndAnalyzeAlerts() {
  const threads = GmailApp.search(SEARCH_QUERY, 0, 10);
  const results = [];

  threads.forEach(thread => {
    const messages = thread.getMessages();
    const lastMsg = messages[messages.length - 1];
    const content = lastMsg.getPlainBody();
    const id = thread.getId();

    // בדיקה אם המזהה כבר עובד (כדי לא לנתח פעמיים)
    if (isProcessed(id)) return;

    const analysis = analyzeWithGemini(content);

    results.push({
      id: id,
      title: lastMsg.getSubject().replace('Google Alert - ', ''),
      summary: analysis.summary,
      score: analysis.score,
      link: extractLink(content),
      date: lastMsg.getDate()
    });
  });

  return results;
}

/**
 * ניתוח טקסט באמצעות Gemini
 */
function analyzeWithGemini(text) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${GEMINI_API_KEY}`;

  const prompt = `
    Analyze the following AI tool alert. 
    1. Score it 0-100 based on: Innovation, Business ROI, and Uniqueness.
    2. Provide a 1-sentence summary in Hebrew.
    Return ONLY JSON: {"score": number, "summary": "string"}

    Text: ${text.substring(0, 2000)}
  `;

  const payload = {
    contents: [{ parts: [{ text: prompt }] }]
  };

  const response = UrlFetchApp.fetch(url, {
    method: 'post',
    contentType: 'application/json',
    payload: JSON.stringify(payload)
  });

  const json = JSON.parse(response.getContentText());
  const rawResult = json.candidates[0].content.parts[0].text;
  return JSON.parse(rawResult.replace(/```json|```/g, ''));
}

/**
 * לוגיקה של כפתורי הפעולה
 */
function handleAction(id, action, data) {
  const props = PropertiesService.getUserProperties();

  if (action === 'YES') {
    // שמירה ל-Google Sheet (מסד הנתונים של ה-MVP)
    const ss = SpreadsheetApp.getActiveSpreadsheet() || SpreadsheetApp.create('Approved_AI_Tools');
    let sheet = ss.getSheetByName('Approved');
    if (!sheet) sheet = ss.insertSheet('Approved');
    sheet.appendRow([new Date(), data.title, data.score, data.link, data.summary]);
  } else if (action === 'MAYBE') {
    // תזכורת לעוד יומיים
    const reminderDate = new Date();
    reminderDate.setDate(reminderDate.getDate() + 2);
    // כאן אפשר להוסיף לוגיקה של Calendar או סימון ב-Gmail
  }

  markAsProcessed(id);
  return { success: true };
}

// פונקציות עזר לשמירת מצב
function isProcessed(id) {
  return PropertiesService.getUserProperties().getProperty('proc_' + id) !== null;
}

function markAsProcessed(id) {
  PropertiesService.getUserProperties().setProperty('proc_' + id, 'true');
}

function extractLink(text) {
  const match = text.match(/\bhttps?:\/\/\S+/gi);
  return match ? match[0] : '#';
}
