            <button onclick="action('${alert.id}', 'MAYBE')" class="flex-1 bg-slate-700 hover:bg-slate-600 py-3 rounded-xl font-bold transition">MAYBE</button>
            <button onclick="action('${alert.id}', 'NO')" class="flex-1 bg-rose-900/50 hover:bg-rose-900 py-3 rounded-xl font-bold text-rose-200 transition">NO</button>
