export interface AnalysisResult {
  snapshot: Competitor[];
  friction: string[];
  errc: {
    eliminate: string[];
    reduce: string[];
    raise: string[];
    create: string[];
  };
  features: {
    title: string;
    description: string;
  }[];
  groundingUrls: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMarketAnalysis = async (ideaDescription: string): Promise<AnalysisResult> => {
  const prompt = `
    Analyze the following product idea as a "Super-Mentor" (fusing Marty Cagan, W. Chan Kim, Paul Graham):
    "${ideaDescription}"

    Research requirements (Use Google Search):
    1. Find exactly the top 3 high-traffic competitors in the AI news/tools aggregator space.
    2. Identify specific market frictions (what users are frustrated with).

    Return the result in JSON format only. Be extremely concise.

    JSON Structure:
    - snapshot: array of 3 competitors (name, traffic, promise).
    - friction: array of 5 friction points.
    - errc: object with keys eliminate, reduce, raise, create (string arrays).
    - features: 3 winning features (title and short description).

    Critical Rules:
    - Language: English.
    - No intros, no outros, no text outside JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            snapshot: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  traffic: { type: Type.STRING },
                  promise: { type: Type.STRING }
                },
                required: ["name", "traffic", "promise"]
              }
            },
            friction: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            errc: {
              type: Type.OBJECT,
              properties: {
                eliminate: { type: Type.ARRAY, items: { type: Type.STRING } },
                reduce: { type: Type.ARRAY, items: { type: Type.STRING } },
                raise: { type: Type.ARRAY, items: { type: Type.STRING } },
                create: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["eliminate", "reduce", "raise", "create"]
            },
            features: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["title", "description"]
              }
            }
          },
          required: ["snapshot", "friction", "errc", "features"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Empty response");

    const parsedData = JSON.parse(text);
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const urls = groundingChunks
      .map((chunk: any) => chunk.web?.uri)
      .filter((uri: string | undefined): uri is string => !!uri);

    return {
      ...parsedData,
      groundingUrls: Array.from(new Set(urls))
    };
  } catch (error) {
    console.error("Market analysis failed:", error);
    throw error;
  }
};

export const analyzeCuratedTool = async (content: string) => {
  const prompt = `
    Analyze this AI tool/news content as "The AI Curator".

    Tasks:
    1. Score it 0-100 (Be strict! Only the best get >80).
    2. Write a 1-sentence "Ethical Summary" that adds value and gives credit.
    3. Identify the "Primary Problem" it solves.

    Content: ${content.substring(0, 3000)}

    Return JSON only:
    { "score": number, "summary": "string", "problem": "string", "title": "string" }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          summary: { type: Type.STRING },
          problem: { type: Type.STRING },
          title: { type: Type.STRING }
        },
        required: ["score", "summary", "problem", "title"]
      }
    }
  });

  return JSON.parse(response.text);
};

