    const id = thread.getId();

    // Skip if we already processed this alert in a previous sync
    if (props.getProperty('status_' + id)) return;

    const message = thread.getMessages()[0];
    const body = message.getPlainBody();
    const subject = message.getSubject().replace('Google Alert - ', '');

    // Extract the primary link (usually the first URL in a Google Alert)
    const linkMatch = body.match(/https?:\/\/[^\s]+(?=\n|\r)/);
    const link = linkMatch ? linkMatch[0] : '#';

    try {
      const analysis = callGemini(body);
      processedData.push({
        id: id,
        title: subject,
        link: link,
        score: analysis.score,
        summary: analysis.summary,
        problem: analysis.problem
      });
    } catch (e) {
      console.error("Failed to analyze: " + id, e);
    }
  });

  return processedData;
}

/**
 * AI ANALYZER: Communicates with Gemini API
 */
function callGemini(text) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite-latest:generateContent?key=${GEMINI_API_KEY}`;

  const prompt = `
    Analyze this AI tool news alert as a Product Mentor.
    Strictly score it 0-100 based on 'Value' and 'Innovation'.
    Write a 1-sentence "Ethical Summary" (give credit to source).
    Identify the "Core Problem" it solves.
    Return ONLY JSON: {"score": number, "summary": "string", "problem": "string"}

    Content: ${text.substring(0, 1500)}
  `;

  const payload = { contents: [{ parts: [{ text: prompt }] }] };
  const options = {
    method: 'post',
    contentType: 'application/json',
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  const response = UrlFetchApp.fetch(url, options);
  const json = JSON.parse(response.getContentText());
  const rawText = json.candidates[0].content.parts[0].text;

  // Clean up markdown block if present
  const cleanedJson = rawText.replace(/```json|```/g, '').trim();
  return JSON.parse(cleanedJson);
}

/**
 * PERSISTENCE: Mark as processed so it doesn't reappear
 */
function updateStatus(id, action) {
  PropertiesService.getUserProperties().setProperty('status_' + id, action);
  return true;
}
