        card.className = 'card p-8 rounded-3xl shadow-2xl';
        card.id = 'card-' + item.id;
        card.innerHTML = `
          <div class="flex justify-between items-start mb-6">
            <div class="max-w-[75%]">
              <h2 class="text-2xl font-black text-white leading-tight">${item.title}</h2>
              <p class="text-blue-500 text-xs font-bold uppercase mt-2 tracking-widest">${item.problem}</p>
