            <div class="text-4xl font-black ${item.score > 75 ? 'text-emerald-400' : 'text-orange-400'}">${item.score}</div>
          </div>

          <p class="text-gray-400 text-lg leading-relaxed italic mb-8">"${item.summary}"</p>

          <div class="flex flex-col sm:flex-row gap-3">
            <button onclick="action('${item.id}', 'YES')" class="flex-1 py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-black rounded-2xl transition uppercase text-xs tracking-widest">Approve</button>
            <button onclick="action('${item.id}', 'NO')" class="flex-1 py-4 bg-gray-800 hover:bg-gray-700 text-gray-400 font-black rounded-2xl transition uppercase text-xs tracking-widest">Reject</button>
            <a href="${item.link}" target="_blank" class="flex items-center justify-center px-6 py-4 border border-gray-800 rounded-2xl hover:bg-white/5 transition">
               <span class="text-xs font-bold">SOURCE</span>
            </a>
          </div>
        `;
        feed.appendChild(card);
      });
    }

    function action(id, type) {
      const card = document.getElementById('card-' + id);
      card.classList.add('opacity-20', 'pointer-events-none');

      google.script.run
        .withSuccessHandler(() => {
          card.remove();
          if (document.getElementById('feed').children.length === 0) {
             sync(); // Auto-refresh if empty
          }
        })
        .updateStatus(id, type);
    }
  </script>
</body>
</html>
