function syncAlerts() {
  const threads = GmailApp.search(SEARCH_QUERY, 0, 10);
  const results = [];

  threads.forEach(thread => {
    const messages = thread.getMessages();
    const lastMsg = messages[messages.length - 1];
    const content = lastMsg.getPlainBody();
    const id = thread.getId();

    try {
      const analysis = analyzeWithGemini(content);
      results.push({
        id: id,
        title: lastMsg.getSubject().replace('Google Alert - ', ''),
        summary: analysis.summary,
        score: analysis.score,
        problem: analysis.problem,
        link: extractLink(content),
        date: lastMsg.getDate()
      });
    } catch(e) { console.error("Error analyzing thread " + id, e); }
  });

  return results;
}

function analyzeWithGemini(text) {
  const url = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite-latest:generateContent?key=' + GEMINI_API_KEY;
  const prompt = "Analyze this AI tool alert. Score 0-100 on ROI. 1-sentence summary with credit. Identify core problem. Return JSON ONLY: {\\\"score\\\": number, \\\"summary\\\": \\\"string\\\", \\\"problem\\\": \\\"string\\\"}. Text: " + text.substring(0, 1500);

  const payload = { contents: [{ parts: [{ text: prompt }] }] };
  const response = UrlFetchApp.fetch(url, { 
    method: 'post', 
    contentType: 'application/json', 
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  });

  const json = JSON.parse(response.getContentText());
  const rawText = json.candidates[0].content.parts[0].text;
  return JSON.parse(rawText.replace(/\\\`\\\`\\\`json|\\\`\\\`\\\`/g, '').trim());
}

function extractLink(text) { 
  const m = text.match(/https?:\\/\\/\\S+/); 
