  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [view, setView] = useState<'analysis' | 'spec' | 'sync'>('analysis');

  // RSS Sync States
  const [rssUrl, setRssUrl] = useState(() => localStorage.getItem('google_alerts_rss_url') || '');
  const [isSyncing, setIsSyncing] = useState(false);
  const [fetchedAlerts, setFetchedAlerts] = useState<any[]>([]);
  const [approvedTools, setApprovedTools] = useState<any[]>(() => {
    const saved = localStorage.getItem('approved_ai_tools');
    return saved ? JSON.parse(saved) : [];
  });

  const ideaDescription = `
    The AI Curator:
    Founder leverages 630k YouTube subs experience in curation.
    Mechanism: Automated scanning + Human filter (Top 1% only).
    Output: Summaries with strict source credits.
    Model: Premium Affiliate Marketing of high-quality tools only.
  `;

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const result = await getMarketAnalysis(ideaDescription);
        setData(result);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    localStorage.setItem('approved_ai_tools', JSON.stringify(approvedTools));
    localStorage.setItem('google_alerts_rss_url', rssUrl);
