    setIsSyncing(true);
    try {
      // שימוש ב-allorigins כדי לעקוף בעיות CORS של דפדפנים
      const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(rssUrl)}`;
      const response = await fetch(proxyUrl);
      const json = await response.json();

      const parser = new DOMParser();
      const xmlDoc = parser.parseFromString(json.contents, "text/xml");
      const entries = Array.from(xmlDoc.querySelectorAll("entry")).slice(0, 10);

      const analyzedItems = await Promise.all(entries.map(async (entry) => {
        const title = entry.querySelector("title")?.textContent || "Unknown Tool";
        const content = entry.querySelector("content")?.textContent || "";
        const link = entry.querySelector("link")?.getAttribute("href") || "#";
        const id = entry.querySelector("id")?.textContent || Math.random().toString();

        // ניתוח AI לכל אייטם מה-Feed
        const analysis = await analyzeCuratedTool(content || title);

        return {
          id,
          title: title.replace(/<b>|<\/b>/g, ""),
          summary: analysis.summary,
          score: analysis.score,
          problem: analysis.problem,
          link
        };
      }));

      setFetchedAlerts(analyzedItems);
    } catch (e) {
      console.error("Sync Error:", e);
      alert("הסנכרון נכשל. וודא שכתובת ה-RSS תקינה.");
    } finally {
      setIsSyncing(false);
    }
