  { id: 'creative', name: 'Creative Arts', subfields: ['Image Gen', 'Video Gen', 'Music Composition', 'Copywriting'] },
  { id: 'dev', name: 'Software Engineering', subfields: ['Code Generation', 'DevOps AI', 'Automated Testing', 'UI Design'] },
  { id: 'edu', name: 'Education', subfields: ['Personalized Learning', 'Automated Grading', 'Skill Gap Analysis'] },
