    const fetchData = async () => {
      try {
        setLoading(true);
        const result = await getMarketAnalysis(ideaDescription);
        setData(result);

        setFetchingCompanies(true);
        const ecosystem = await fetchAICompanies();
        setCompanies(ecosystem);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
        setFetchingCompanies(false);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    localStorage.setItem('curator_approved_tools', JSON.stringify(approvedTools));
