    setIsSyncing(true);
    try {
      const news = await discoverTrendingAINews(filters);
      setDiscoveredAlerts(news);
    } catch (e) {
      console.error("Discovery Error:", e);
      alert("Discovery failed. Please try again.");
    } finally {
      setIsSyncing(false);
    }
  };

