import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, CurationFilters, AICompany, RefinedItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getMarketAnalysis = async (ideaDescription: string): Promise<AnalysisResult> => {
  const prompt = `
    Analyze the following product idea as a "Super-Mentor" (fusing Marty Cagan, W. Chan Kim, Paul Graham):
    "${ideaDescription}"

    Research requirements (Use Google Search):
    1. Find exactly the top 3 high-traffic competitors in the AI news/tools aggregator space.
    2. Identify specific market frictions (what users are frustrated with).

    Return the result in JSON format only.
    Language: Hebrew.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            snapshot: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  traffic: { type: Type.STRING },
                  promise: { type: Type.STRING }
                },
                required: ["name", "traffic", "promise"]
              }
            },
            friction: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            errc: {
              type: Type.OBJECT,
              properties: {
                eliminate: { type: Type.ARRAY, items: { type: Type.STRING } },
                reduce: { type: Type.ARRAY, items: { type: Type.STRING } },
                raise: { type: Type.ARRAY, items: { type: Type.STRING } },
                create: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["eliminate", "reduce", "raise", "create"]
            },
            features: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["title", "description"]
              }
            }
          },
          required: ["snapshot", "friction", "errc", "features"]
        }
      }
    });

    const parsedData = JSON.parse(response.text);
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const urls = groundingChunks
      .map((chunk: any) => chunk.web?.uri)
      .filter((uri: string | undefined): uri is string => !!uri);

    return {
      ...parsedData,
      groundingUrls: Array.from(new Set(urls))
    };
  } catch (error) {
    console.error("Market analysis failed:", error);
    throw error;
  }
};

export const fetchAICompanies = async (): Promise<AICompany[]> => {
  const prompt = `
    Scan the current AI ecosystem and return a list of AI Giants and Promising Startups.
    Return JSON only.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text).companies;
};

export const discoverTrendingAINews = async (filters: CurationFilters) => {
  const prompt = `
    Perform a high-precision scan for AI news (including in-development/beta items like 'Claude Code' or leaks):
    - Domains: ${filters.selectedDomains.join(", ")}
    - Companies: ${filters.selectedCompanies.join(", ")}

    Return JSON only. Language: Hebrew.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text).items;
};

export const refineCuratedContent = async (rawItem: any): Promise<RefinedItem> => {
  const prompt = `
    Act as "The AI Curator". Refine this raw news/tool item into my signature style.
    Raw Item: ${JSON.stringify(rawItem)}

    Rules:
    1. Hook: A catchy, non-original headline.
    2. Justification: Why did this make the "1% Filter"? (Speed, Innovation, ROI).
    3. Verdict: A sharp, authoritative opinion.
    4. Language: Hebrew.

    Return JSON only:
    { "hook": "string", "justification": "string", "verdict": "string" }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json"
    }
  });

  const refined = JSON.parse(response.text);
  return {
    ...refined,
    id: rawItem.id,
    originalLink: rawItem.link,
    originalTitle: rawItem.title
  };
};

export const generateMascotImage = async (): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: 'A high-end cinematic render of a humanoid robot head and shoulders, inspired by Sonny from I, Robot but designed as a premium Apple product. Ceramic white finish, titanium frame, translucent glass faceplate, studio lighting, deep space background with subtle aurora glow. High resolution, 4k, minimalist aesthetic.',
        },
      ],
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return '';
};

