    Return JSON only:
    { "companies": [ { "id": "string", "name": "string", "type": "giant" | "promising", "description": "1-sentence summary in Hebrew" } ] }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text).companies;
};

export const discoverTrendingAINews = async (filters: CurationFilters) => {
  const prompt = `
    Perform a high-precision scan for AI news based on these criteria:
    - Selected Domains: ${filters.selectedDomains.join(", ")}
    - Subfields: ${filters.selectedSubfields.join(", ")}
    - Companies to track: ${filters.selectedCompanies.join(", ")}

    CRITICAL: Search for IN-DEVELOPMENT items, beta releases, leaks, GitHub repositories (like "Claude Code"), and research breakthroughs.
    Focus on news from the last 48 hours.

    Act as "The AI Curator" (Top 1% filter). Be very critical.

    For each item:
    1. Score it 0-100 on impact.
    2. Write a 1-sentence summary in Hebrew.
    3. Identify the "Primary Problem" it solves in Hebrew.

    Return JSON only:
    { "items": [ { "id": "string", "title": "string", "score": number, "summary": "string", "problem": "string", "link": "string" } ] }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text).items;
};

export const refineCuratedContent = async (rawItem: any): Promise<RefinedItem> => {
  const prompt = `
    Act as "The AI Curator". Refine this raw news/tool item into my signature style.
    Raw Item: ${JSON.stringify(rawItem)}

    Rules:
    1. Hook: A catchy, cinematic headline (not the original one).
    2. 1% Justification: Why did I approve this? (Speed? Innovation? ROI?).
    3. Curator's Verdict: A short, sharp opinion.
    4. Language: Hebrew.

    Return JSON only:
    { "hook": "string", "justification": "string", "verdict": "string" }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json"
    }
  });

  const refined = JSON.parse(response.text);
  return {
    ...refined,
    id: rawItem.id,
    originalLink: rawItem.link,
    originalTitle: rawItem.title
  };
};

export const generateMascotImage = async (): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: 'A high-end cinematic studio render of a humanoid robot head and shoulders. Inspired by Sonny from I, Robot. Aesthetic: Apple Cosmic. Ceramic white finish, polished titanium frame, translucent glass faceplate with internal circuitry glowing subtly. Pure black background with a very subtle purple/teal nebula glow (Aurora). Lighting: Professional studio softbox lighting. High resolution, 4k, hyper-detailed, minimalist.',
        },
      ],
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return '';
};

