export const discoverTrendingAINews = async (filters: CurationFilters) => {
  const prompt = `
    Perform a high-precision scan for AI news based on these criteria:
    - Selected Domains: ${filters.selectedDomains.join(", ")}
    - Companies to track: ${filters.selectedCompanies.join(", ")}

    CRITICAL: Search for IN-DEVELOPMENT items, beta releases, leaks, GitHub repositories (like "Claude Code"), and research breakthroughs.
    Focus on news from the last 48 hours.

    Act as "The AI Curator" (Top 1% filter). Be very critical.

    For each item:
    1. Score it 0-100 on impact.
    2. Write a 1-sentence summary in Hebrew.
    3. Identify the "Primary Problem" it solves in Hebrew.

    Return JSON only:
    { "items": [ { "id": "string", "title": "string", "score": number, "summary": "string", "problem": "string", "link": "string" } ] }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text).items;
};

export const refineCuratedContent = async (rawItem: any): Promise<RefinedItem> => {
  const prompt = `
    Act as "The AI Curator", fusing the mental models of Marty Cagan (Value/Usability), W. Chan Kim (Blue Ocean innovation), and Paul Graham (Underdog/High Signal).

    Refine this raw AI news/tool into a premium, authoritative post.
    Raw Data: ${JSON.stringify(rawItem)}

    The Output MUST follow this strict structure:
    1. Hook: A catchy, cinematic headline that focuses on the UNFAIR ADVANTAGE this tool/news provides.
    2. 1% Justification: Explain why this passed our strict human filter. Focus on Value, Innovation, or high ROI for the user.
    3. Curator's Verdict: A short, sharp, "Underdog" opinion. Do not be generic. Be strict and opinionated.

    Language: Hebrew.

    Return JSON only:
    { "hook": "string", "justification": "string", "verdict": "string" }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json"
    }
  });

  const refined = JSON.parse(response.text);
  return {
    ...refined,
    id: rawItem.id,
    originalLink: rawItem.link,
    originalTitle: rawItem.title
  };
};

export const generateMascotImage = async (): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: 'A high-end cinematic studio render of a humanoid robot head and shoulders, inspired by Sonny from I, Robot but redesigned as a premium Apple product. Ceramic white finish, polished titanium frame, translucent glass faceplate showing internal blue micro-LED circuitry. Lighting: Studio softbox, high-key. Background: Deep space black with a subtle teal/purple nebula glow. 8k, photorealistic, minimalist, Apple Keynote aesthetic.',
        },
      ],
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return '';
};

