export const discoverTrendingAINews = async (filters: CurationFilters) => {
  const prompt = `
    Perform a high-precision scan for AI news (including in-development items and leaks):
    Domains: ${filters.selectedDomains.join(", ")}
    Companies: ${filters.selectedCompanies.join(", ")}

    Act as "The AI Curator" (Top 1% filter).
    Return JSON only. Language: Hebrew.
    Schema: { "items": [ { "id": "string", "title": "string", "score": number, "summary": "string", "link": "string" } ] }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json"
      }
    });

    const data = JSON.parse(response.text);
    const items = data.items || [];
    return items.map((item: any, idx: number) => ({
      ...item,
      id: item.id || `news-${Date.now()}-${idx}`
    }));
  } catch (error) {
    console.error("Discover trending news failed:", error);
    return [];
  }
};

export const refineCuratedContent = async (rawItem: any): Promise<RefinedItem> => {
  const prompt = `
    Act as "The AI Curator" (fusing Marty Cagan, W. Chan Kim, Paul Graham).
    Rewrite this raw news item into a structured review:
    1. Hook: A catchy, premium headline.
    2. 1% Justification: Why did this pass our strict filter? (Speed? Innovation? ROI?).
    3. Curator's Verdict: A short, sharp opinion.

    Raw Data: ${JSON.stringify(rawItem)}

    Language: Hebrew.
    Return JSON only:
    { "hook": "string", "justification": "string", "verdict": "string" }
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json"
    }
  });

  const refined = JSON.parse(response.text);
  return {
    ...refined,
    id: rawItem.id || `refined-${Date.now()}`,
    originalLink: rawItem.link || '#',
    originalTitle: rawItem.title || 'Untitled'
  };
};

export const generateBrandMascot = async (): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: 'A high-end cinematic render of a humanoid robot head and shoulders, inspired by Sonny from I, Robot but styled as a premium Apple product. Ceramic white polished finish, titanium accents, translucent glass components with subtle internal glow. Deep space background with a hint of purple aurora. Studio lighting, 8k resolution, minimalist.',
        },
      ],
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return '';
};

import React, { useState, useEffect } from 'react';
import { 
  getMarketAnalysis, 
  discoverTrendingAINews, 
  fetchAICompanies, 
  refineCuratedContent, 
  generateBrandMascot 
} from './services/geminiService';
