const AI_DOMAINS: AIDomain[] = [
  { id: 'health', name: 'Health & Biotech', subfields: ['Drug Discovery', 'Diagnostics', 'Personalized Medicine', 'Genomics'] },
  { id: 'finance', name: 'Finance', subfields: ['Algorithmic Trading', 'Fraud Detection', 'Risk Management', 'Personal Finance'] },
  { id: 'creative', name: 'Creative Arts', subfields: ['Image Gen', 'Video Gen', 'Music Composition', 'Copywriting'] },
  { id: 'dev', name: 'Software Engineering', subfields: ['Code Generation', 'DevOps AI', 'Automated Testing', 'UI Design'] },
  { id: 'edu', name: 'Education', subfields: ['Personalized Learning', 'Automated Grading', 'Skill Gap Analysis'] },
  { id: 'legal', name: 'Legal & Compliance', subfields: ['Contract Analysis', 'Case Research', 'Regulatory Tracking'] },
  { id: 'marketing', name: 'Marketing & Sales', subfields: ['Customer Segmentation', 'Sentiment Analysis', 'Ad Optimization'] },
  { id: 'robotics', name: 'Robotics & Hardware', subfields: ['Computer Vision', 'Autonomous Systems', 'Edge AI'] }
];

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [view, setView] = useState<'analysis' | 'spec' | 'discovery' | 'public'>('analysis');

  // Brand Assets
  const [mascotUrl, setMascotUrl] = useState<string>(() => localStorage.getItem('curator_mascot') || '');
  const [isGeneratingMascot, setIsGeneratingMascot] = useState(false);

  // Curation Filters States
  const [companies, setCompanies] = useState<AICompany[]>([]);
  const [fetchingCompanies, setFetchingCompanies] = useState(false);
  const [filters, setFilters] = useState<CurationFilters>({
    selectedDomains: [],
    selectedSubfields: [],
    selectedCompanies: []
  });

  // Automated Discovery States
  const [isSyncing, setIsSyncing] = useState(false);
  const [discoveredAlerts, setDiscoveredAlerts] = useState<any[]>([]);
  const [approvedTools, setApprovedTools] = useState<any[]>(() => {
    const saved = localStorage.getItem('curator_approved_tools');
    return saved ? JSON.parse(saved) : [];
  });

  // Refined Content State (Task A)
  const [refinedItems, setRefinedItems] = useState<RefinedItem[]>(() => {
    const saved = localStorage.getItem('curator_refined_items');
    return saved ? JSON.parse(saved) : [];
  });
  const [refiningId, setRefiningId] = useState<string | null>(null);

  const ideaDescription = `
    The AI Curator:
    Founder leverages 630k YouTube subs experience in curation.
    Mechanism: Automated scanning + Human filter (Top 1% only).
    Output: Summaries with strict source credits.
    Model: Premium Affiliate Marketing.
  `;

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const result = await getMarketAnalysis(ideaDescription);
        setData(result);
        setFetchingCompanies(true);
        const ecosystem = await fetchAICompanies();
        setCompanies(ecosystem);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
        setFetchingCompanies(false);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    localStorage.setItem('curator_approved_tools', JSON.stringify(approvedTools));
    localStorage.setItem('curator_refined_items', JSON.stringify(refinedItems));
    localStorage.setItem('curator_mascot', mascotUrl);
  }, [approvedTools, refinedItems, mascotUrl]);

  const handleDiscovery = async () => {
    if (filters.selectedDomains.length === 0 && filters.selectedCompanies.length === 0) {
      alert("נא לבחור לפחות תחום אחד או חברה אחת לסינון.");
      return;
    }
    setIsSyncing(true);
    try {
      const news = await discoverTrendingAINews(filters);
      setDiscoveredAlerts(news);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleRefineItem = async (tool: any) => {
    setRefiningId(tool.id);
    try {
      const refined = await refineCuratedContent(tool);
      setRefinedItems(prev => [refined, ...prev.filter(item => item.id !== tool.id)]);
    } catch (e) {
      console.error(e);
    } finally {
      setRefiningId(null);
    }
  };

  const handleMascotGenerate = async () => {
    setIsGeneratingMascot(true);
    try {
      const url = await generateBrandMascot();
      setMascotUrl(url);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGeneratingMascot(false);
    }
  };

  const toggleDomain = (domainId: string) => {
    setFilters(prev => {
      const isSelected = prev.selectedDomains.includes(domainId);
      const newDomains = isSelected 
        ? prev.selectedDomains.filter(id => id !== domainId)
        : [...prev.selectedDomains, domainId];
      const domain = AI_DOMAINS.find(d => d.id === domainId);
      const newSubfields = isSelected && domain
        ? prev.selectedSubfields.filter(sf => !domain.subfields.includes(sf))
        : prev.selectedSubfields;
      return { ...prev, selectedDomains: newDomains, selectedSubfields: newSubfields };
    });
  };

  const handleApprove = (alertId: string) => {
    const tool = discoveredAlerts.find(a => a.id === alertId);
    if (tool) {
      setApprovedTools([tool, ...approvedTools]);
      setDiscoveredAlerts(discoveredAlerts.filter(a => a.id !== alertId));
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-[#000] text-white p-6">
        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-6"></div>
        <h1 className="text-2xl font-bold italic tracking-tighter uppercase">The AI Curator</h1>
        <p className="text-gray-500 font-medium">Initializing Cosmic Engine...</p>
      </div>
    );
  }

  // --- PUBLIC LANDING PAGE (APPLE COSMIC) ---
  if (view === 'public') {
    return (
      <div className="min-h-screen bg-[#000] text-white selection:bg-purple-500 selection:text-white relative overflow-x-hidden" dir="rtl">
        {/* Background Gradients */}
