    Language: Hebrew.
    Return JSON only:
    { "items": [ { "id": "string", "title": "string", "score": number, "summary": "string", "link": "string" } ] }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
