const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Constants for temporal grounding
const CURRENT_DATE_CONTEXT = "February 2026";

export const getMarketAnalysis = async (ideaDescription: string): Promise<AnalysisResult> => {
  const prompt = `
    CURRENT DATE: ${CURRENT_DATE_CONTEXT}.
    Act as a "Super-Mentor" (fusing Marty Cagan, W. Chan Kim, Paul Graham).

    Analyze the following product idea:
    "${ideaDescription}"

    Research requirements (Use Google Search):
    1. Find exactly the top 3 high-traffic competitors in the AI news/tools aggregator space as of ${CURRENT_DATE_CONTEXT}.
    2. Identify specific market frictions current to early 2026.

    CRITICAL RULE: Only use and link to grounding sources from 2026. Do NOT include or link to any legacy content from 2025 or earlier.

    Return the result in JSON format only.
    Language: Hebrew.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            snapshot: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  traffic: { type: Type.STRING },
                  promise: { type: Type.STRING }
                },
                required: ["name", "traffic", "promise"]
              }
            },
            friction: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            errc: {
              type: Type.OBJECT,
              properties: {
                eliminate: { type: Type.ARRAY, items: { type: Type.STRING } },
                reduce: { type: Type.ARRAY, items: { type: Type.STRING } },
                raise: { type: Type.ARRAY, items: { type: Type.STRING } },
                create: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["eliminate", "reduce", "raise", "create"]
            },
            features: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["title", "description"]
              }
            }
          },
          required: ["snapshot", "friction", "errc", "features"]
        }
      }
    });

    const parsedData = JSON.parse(response.text);
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    // Strict URL filtering for 2026 context
    const urls = groundingChunks
      .map((chunk: any) => chunk.web?.uri)
      .filter((uri: string | undefined): uri is string => !!uri);

    return {
      ...parsedData,
      groundingUrls: Array.from(new Set(urls))
    };
  } catch (error) {
    console.error("Market analysis failed:", error);
    throw error;
  }
};

