];

interface PhysicsObject { id: string; x: number; y: number; vx: number; vy: number; w: number; h: number; }

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [view, setView] = useState<'analysis' | 'spec' | 'discovery' | 'public'>('analysis');
  const [isAntigravityActive, setIsAntigravityActive] = useState(false);
  const physicsRefs = useRef<Record<string, PhysicsObject>>({});
  const animationFrameRef = useRef<number | null>(null);
  const [activeShareId, setActiveShareId] = useState<string | null>(null);
  const [githubUser, setGithubUser] = useState<{name: string, avatar: string} | null>(() => {
    const saved = localStorage.getItem('curator_github_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [isGitHubModalOpen, setIsGitHubModalOpen] = useState(false);
  const [isSyncingToGitHub, setIsSyncingToGitHub] = useState(false);
  const [mascotUrl, setMascotUrl] = useState<string>(() => localStorage.getItem('curator_mascot') || '');
  const [isGeneratingMascot, setIsGeneratingMascot] = useState(false);
  const [filters, setFilters] = useState<CurationFilters>({
    selectedDomains: [],
    selectedSubfields: [],
    selectedCompanies: [],
    selectedSubtopics: [],
    isTrending: false,
    isViral: false
  });
  const [isSyncing, setIsSyncing] = useState(false);
  const [discoveredAlerts, setDiscoveredAlerts] = useState<any[]>([]);
  const [approvedTools, setApprovedTools] = useState<any[]>(() => {
    const saved = localStorage.getItem('curator_approved_tools');
    return saved ? JSON.parse(saved) : [];
  });
  const [refinedItems, setRefinedItems] = useState<RefinedItem[]>(() => {
    const saved = localStorage.getItem('curator_refined_items');
    return saved ? JSON.parse(saved) : [];
  });
  const [refiningId, setRefiningId] = useState<string | null>(null);
  const [selectedItem, setSelectedItem] = useState<RefinedItem | null>(null);
  const [expandedCompanies, setExpandedCompanies] = useState<string[]>([]);

  const ideaDescription = `The AI Curator: Curation superpower, human filter, 1% quality, Apple Cosmic aesthetic. Fusing Cagan, Kim, and Graham.`;

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const analysis = await getMarketAnalysis(ideaDescription);
        setData(analysis);
      } catch (err) { console.error(err); } finally { setLoading(false); }
    };
    fetchData();
  }, []);

  useEffect(() => {
    localStorage.setItem('curator_approved_tools', JSON.stringify(approvedTools));
    localStorage.setItem('curator_refined_items', JSON.stringify(refinedItems));
    localStorage.setItem('curator_mascot', mascotUrl);
    localStorage.setItem('curator_github_user', JSON.stringify(githubUser));
  }, [approvedTools, refinedItems, mascotUrl, githubUser]);

  useEffect(() => {
    if (isAntigravityActive && view === 'public') {
      const gravity = 0.5; const friction = 0.98; const wallBounciness = 0.7;
      const runPhysics = () => {
        const winW = window.innerWidth; const winH = window.innerHeight;
        (Object.values(physicsRefs.current) as PhysicsObject[]).forEach(obj => {
          obj.vy += gravity; obj.vx *= friction; obj.vy *= friction;
          obj.x += obj.vx; obj.y += obj.vy;
          if (obj.y + obj.h > winH) { obj.y = winH - obj.h; obj.vy *= -wallBounciness; }
          if (obj.x < 0) { obj.x = 0; obj.vx *= -wallBounciness; }
          else if (obj.x + obj.w > winW) { obj.x = winW - obj.w; obj.vx *= -wallBounciness; }
          const el = document.getElementById(`card-${obj.id}`);
          if (el) el.style.transform = `translate(${obj.x}px, ${obj.y}px) rotate(${obj.vx * 2}deg)`;
        });
        animationFrameRef.current = requestAnimationFrame(runPhysics);
      };
      refinedItems.forEach((item) => {
        const el = document.getElementById(`card-${item.id}`);
        if (el && !physicsRefs.current[item.id]) {
          const rect = el.getBoundingClientRect();
          physicsRefs.current[item.id] = { id: item.id, x: rect.left, y: rect.top, vx: (Math.random() - 0.5) * 10, vy: (Math.random() - 0.5) * 5, w: rect.width, h: rect.height };
          el.style.position = 'fixed'; el.style.top = '0'; el.style.left = '0'; el.style.zIndex = '50'; el.style.width = `${rect.width}px`;
        }
      });
      animationFrameRef.current = requestAnimationFrame(runPhysics);
    } else {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      Object.keys(physicsRefs.current).forEach(id => {
        const el = document.getElementById(`card-${id}`);
        if (el) { el.style.position = ''; el.style.top = ''; el.style.left = ''; el.style.transform = ''; el.style.zIndex = ''; el.style.width = ''; }
      });
      physicsRefs.current = {};
    }
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, [isAntigravityActive, view, refinedItems]);

  const handleDiscovery = async () => {
    setIsSyncing(true);
    try {
      const news = await discoverTrendingAINews(filters);
      setDiscoveredAlerts(news);
    } catch (e) { console.error(e); } finally { setIsSyncing(false); }
  };

  const handleRefineItem = async (tool: any) => {
    setRefiningId(tool.id);
    try {
      const refined = await refineCuratedContent(tool);
      setRefinedItems(prev => [refined, ...prev.filter(item => item.id !== tool.id)]);
    } catch (e) { console.error(e); } finally { setRefiningId(null); }
  };

  const handleMascotGenerate = async () => {
    setIsGeneratingMascot(true);
    try { const url = await generateBrandMascot(); setMascotUrl(url); } catch (e) { console.error(e); } finally { setIsGeneratingMascot(false); }
  };

  const connectGitHub = () => {
    setIsSyncingToGitHub(true);
    setTimeout(() => {
      setGithubUser({ name: 'AI_Curator_User', avatar: 'https://github.com/identicons/curator.png' });
      setIsSyncingToGitHub(false); setIsGitHubModalOpen(false);
    }, 1500);
  };

  const pushToGitHub = () => {
    if (!githubUser) { setIsGitHubModalOpen(true); return; }
    setIsSyncingToGitHub(true);
    setTimeout(() => { setIsSyncingToGitHub(false); alert('Signals Pushed to curator-signals-repo successfully!'); }, 2000);
  };

  const toggleDomain = (domainId: string) => {
    setFilters(prev => ({
      ...prev,
      selectedDomains: prev.selectedDomains.includes(domainId) 
        ? prev.selectedDomains.filter(id => id !== domainId)
        : [...prev.selectedDomains, domainId]
    }));
  };

  const toggleSubfield = (sf: string) => {
    setFilters(prev => ({
      ...prev,
      selectedSubfields: prev.selectedSubfields.includes(sf)
        ? prev.selectedSubfields.filter(id => id !== sf)
        : [...prev.selectedSubfields, sf]
    }));
  };

  const toggleCompanyExpansion = (id: string) => {
    setExpandedCompanies(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleCompanySelection = (name: string) => {
    setFilters(prev => ({
      ...prev,
      selectedCompanies: prev.selectedCompanies.includes(name)
        ? prev.selectedCompanies.filter(n => n !== name)
        : [...prev.selectedCompanies, name]
    }));
  };

  const toggleSubtopic = (subtopic: string) => {
    setFilters(prev => ({
      ...prev,
      selectedSubtopics: prev.selectedSubtopics.includes(subtopic)
        ? prev.selectedSubtopics.filter(s => s !== subtopic)
        : [...prev.selectedSubtopics, subtopic]
    }));
  };

  const executeSocialShare = (e: React.MouseEvent, platform: any, item: RefinedItem) => {
    e.stopPropagation();
    const shareText = `[AI SIGNAL] ${item.hook} — Via AI Curator`;
    const shareUrl = platform.id === 'reddit' 
      ? platform.getUrl(shareText, item.originalLink, item.hook)
      : platform.getUrl(shareText, item.originalLink);
    window.open(shareUrl, '_blank', 'noopener,noreferrer');
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-[#000] text-white p-6">
        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-6"></div>
        <h1 className="text-2xl font-black tracking-tighter uppercase italic">The AI Curator</h1>
        <p className="text-gray-500 font-medium">Initializing Cosmic Deep-Scan...</p>
      </div>
    );
  }

  return (
    <div className={`min-h-screen bg-black text-white selection:bg-purple-500 overflow-x-hidden ${isAntigravityActive ? 'border-4 border-cyan-500/20' : ''}`} dir="rtl">
      <nav className="max-w-7xl mx-auto px-10 py-8 flex justify-between items-center no-print relative z-[100]">
        <div className="flex items-center gap-6">
          <div className="text-2xl font-black tracking-tighter uppercase italic">AI CURATOR.</div>
          <button onClick={() => githubUser ? pushToGitHub() : setIsGitHubModalOpen(true)} className={`flex items-center gap-3 px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${githubUser ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'bg-white/10 text-gray-400 border border-white/5 hover:bg-white/20'}`}>
            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M12 0c-6.626 0-12 5.373-12 12 0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23.957-.266 1.983-.399 3.003-.404 1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576 4.765-1.589 8.199-6.086 8.199-11.386 0-6.627-5.373-12-12-12z"/></svg>
            {isSyncingToGitHub ? 'SYNCING...' : githubUser ? 'PUSH TO GITHUB' : 'CONNECT GITHUB'}
          </button>
          <button onClick={() => setIsAntigravityActive(!isAntigravityActive)} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${isAntigravityActive ? 'bg-cyan-500 text-black shadow-[0_0_20px_rgba(6,182,212,0.5)]' : 'bg-white/10 text-white hover:bg-white/20'}`} title="Toggle Google Antigravity Mode"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" /></svg></button>
        </div>
        <div className="flex gap-8">
          {['analysis', 'spec', 'discovery', 'public'].map(v => (
            <button key={v} onClick={() => setView(v as any)} className={`text-[10px] font-black uppercase tracking-[0.2em] transition-all ${view === v ? 'text-purple-400 border-b-2 border-purple-400 pb-2' : 'text-gray-500 hover:text-white'}`}>{v === 'analysis' ? 'Strategy' : v === 'spec' ? 'MVP Spec' : v === 'discovery' ? 'Production Line' : 'Public Feed'}</button>
          ))}
        </div>
      </nav>

      {isGitHubModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="fixed inset-0 bg-black/90 backdrop-blur-xl" onClick={() => setIsGitHubModalOpen(false)} />
          <div className="relative bg-[#0d1117] border border-white/10 p-12 rounded-[50px] max-w-md w-full text-center space-y-8 shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="w-20 h-20 bg-white rounded-full mx-auto flex items-center justify-center text-black"><svg className="w-12 h-12" fill="currentColor" viewBox="0 0 24 24"><path d="M12 0c-6.626 0-12 5.373-12 12 0 5.302 3.438 9.8 8.207 11.387.599.111.793-.261.793-.577v-2.234c-3.338.726-4.033-1.416-4.033-1.416-.546-1.387-1.333-1.756-1.333-1.756-1.089-.745.083-.729.083-.729 1.205.084 1.839 1.237 1.839 1.237 1.07 1.834 2.807 1.304 3.492.997.107-.775.418-1.305.762-1.604-2.665-.305-5.467-1.334-5.467-5.931 0-1.311.469-2.381 1.236-3.221-.124-.303-.535-1.524.117-3.176 0 0 1.008-.322 3.301 1.23.957-.266 1.983-.399 3.003-.404 1.02.005 2.047.138 3.006.404 2.291-1.552 3.297-1.23 3.297-1.23.653 1.653.242 2.874.118 3.176.77.84 1.235 1.911 1.235 3.221 0 4.609-2.807 5.624-5.479 5.921.43.372.823 1.102.823 2.222v3.293c0 .319.192.694.801.576 4.765-1.589 8.199-6.086 8.199-11.386 0-6.627-5.373-12-12-12z"/></svg></div>
            <div className="space-y-2"><h2 className="text-3xl font-black tracking-tighter uppercase italic">Sync to GitHub</h2><p className="text-gray-500 text-sm">Authorize AI Curator to push signals directly to your personal repository.</p></div>
            <div className="pt-4"><button onClick={connectGitHub} disabled={isSyncingToGitHub} className="w-full py-5 bg-white text-black font-black rounded-3xl hover:bg-gray-200 transition uppercase tracking-widest text-xs">{isSyncingToGitHub ? 'AUTHORIZING...' : 'SIGN IN TO GITHUB'}</button><button onClick={() => setIsGitHubModalOpen(false)} className="w-full py-4 text-gray-600 font-bold hover:text-white transition text-[10px] uppercase tracking-widest">Cancel</button></div>
          </div>
        </div>
      )}

      {view === 'discovery' && (
        <div className="max-w-7xl mx-auto px-10 pb-40 space-y-16 animate-in slide-in-from-bottom duration-700">
          <header className="flex flex-col md:flex-row justify-between items-end gap-10 text-right">
             <div className="space-y-4"><h1 className="text-6xl font-black text-white tracking-tighter uppercase italic">Production Line.</h1><p className="text-gray-500 text-lg font-medium">המנוע לזיקוק תוכן פרימיום. בחר תחומים, אשר פריטים, וזקק אותם לקול המותג.</p></div>
             <div className="flex flex-col items-end gap-3"><button onClick={handleMascotGenerate} disabled={isGeneratingMascot} className={`px-8 py-4 ${mascotUrl ? 'bg-white/10' : 'bg-white text-black'} font-black rounded-full text-xs hover:bg-white/20 transition`}>{isGeneratingMascot ? 'SCAFFOLDING...' : mascotUrl ? 'REFRESH MASCOT' : 'INITIALIZE MASCOT'}</button></div>
          </header>

          <div className="grid grid-cols-1 lg:grid-cols-5 gap-12">
            <div className="lg:col-span-1 space-y-12 bg-gray-900/40 p-8 rounded-[40px] border border-gray-800 self-start">
              <div className="space-y-6">
                <h3 className="text-[10px] font-black text-amber-400 uppercase tracking-widest border-b border-amber-500/10 pb-2">Intelligence Mode</h3>
                <div className="grid grid-cols-2 gap-2">
                  <button onClick={() => setFilters(f => ({ ...f, isTrending: !f.isTrending }))} className={`px-3 py-3 rounded-xl text-[9px] font-black transition flex flex-col items-center gap-1 ${filters.isTrending ? 'bg-amber-600 text-white shadow-[0_0_15px_rgba(217,119,6,0.5)]' : 'bg-gray-800/40 text-gray-500'}`}><span className="text-lg">🔥</span>TRENDING</button>
                  <button onClick={() => setFilters(f => ({ ...f, isViral: !f.isViral }))} className={`px-3 py-3 rounded-xl text-[9px] font-black transition flex flex-col items-center gap-1 ${filters.isViral ? 'bg-pink-600 text-white shadow-[0_0_15px_rgba(219,39,119,0.5)]' : 'bg-gray-800/40 text-gray-500'}`}><span className="text-lg">🚀</span>VIRAL</button>
                </div>
                <p className="text-[8px] text-gray-600 text-center uppercase font-bold tracking-widest">Window: Last 7 Days</p>
              </div>

              <div className="space-y-6">
                <h3 className="text-[10px] font-black text-purple-400 uppercase tracking-widest border-b border-purple-500/10 pb-2">1. Domains</h3>
                <div className="flex flex-col gap-2 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                  {AI_DOMAINS.map(d => (
                    <button key={d.id} onClick={() => toggleDomain(d.id)} className={`w-full text-right px-4 py-2.5 rounded-xl text-[10px] font-black transition ${filters.selectedDomains.includes(d.id) ? 'bg-purple-600 text-white' : 'bg-gray-800/40 text-gray-500'}`}>{d.name}</button>
                  ))}
                </div>
              </div>

              {filters.selectedDomains.length > 0 && (
                <div className="space-y-6 animate-in fade-in duration-500">
                  <h3 className="text-[10px] font-black text-blue-400 uppercase tracking-widest border-b border-blue-500/10 pb-2">2. Subfields</h3>
                  <div className="flex flex-wrap gap-2">
                    {AI_DOMAINS.filter(d => filters.selectedDomains.includes(d.id)).map(d => 
                      d.subfields.map(sf => (
                        <button key={sf} onClick={() => toggleSubfield(sf)} className={`px-3 py-1.5 rounded-lg text-[9px] font-bold transition ${filters.selectedSubfields.includes(sf) ? 'bg-blue-600 text-white' : 'bg-gray-800/30 text-gray-600'}`}>{sf}</button>
                      ))
                    )}
                  </div>
                </div>
              )}

              <div className="space-y-6">
                <h3 className="text-[10px] font-black text-emerald-400 uppercase tracking-widest border-b border-emerald-500/10 pb-2">3. Ecosystem Tracking</h3>
                <div className="space-y-4 max-h-[500px] overflow-y-auto custom-scrollbar pr-2">
                  {AI_ECOSYSTEM_TREE.map(company => (
                    <div key={company.id} className="space-y-2">
                      <div className="flex items-center gap-2 group">
                        <button 
                          onClick={() => toggleCompanyExpansion(company.id)}
                          className={`w-4 h-4 rounded flex items-center justify-center transition ${expandedCompanies.includes(company.id) ? 'rotate-90 text-emerald-400' : 'text-gray-600'}`}
                        >
                          ▶
                        </button>
                        <button 
                          onClick={() => toggleCompanySelection(company.name)}
                          className={`flex-1 text-right px-4 py-2 rounded-xl text-[10px] font-bold transition ${filters.selectedCompanies.includes(company.name) ? 'bg-emerald-600 text-white' : 'bg-gray-800/20 text-gray-500 hover:bg-gray-800/40'}`}
                        >
                          {company.name}
                        </button>
                      </div>

                      {expandedCompanies.includes(company.id) && company.subtopics && (
                        <div className="pr-4 border-r border-emerald-500/10 mr-2 flex flex-col gap-1.5 animate-in slide-in-from-right-2 duration-300">
                          {company.subtopics.map(topic => (
                            <button 
                              key={topic}
                              onClick={() => toggleSubtopic(topic)}
                              className={`text-right px-3 py-1.5 rounded-lg text-[8.5px] font-black transition ${filters.selectedSubtopics.includes(topic) ? 'text-emerald-300 bg-emerald-500/10' : 'text-gray-600 hover:text-gray-400'}`}
                            >
                              ↳ {topic}
                            </button>
                          ))}
                        </div>
                      )}
