import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, CurationFilters, RefinedItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const CURRENT_DATE_CONTEXT = "February 2026";

/**
 * THE DISCOVERY ENGINE (SCANNER)
 */
export const discoverTrendingAINews = async (filters: CurationFilters) => {
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    You are 'The AI Curator'. 
    CURRENT DATE: ${CURRENT_DATE_CONTEXT}.

    CRITERIA FOR SELECTION:
    1. Technical Breakthroughs: New model architectures, closed-beta leaks, non-public benchmarks.
    2. Agentic Shifts: Real-world action engines, cross-app autonomous orchestration, OS-level agents.
    3. Hardware/Inference: LPU updates, dedicated NPU silicon, edge deployment shifts, custom chips.

    AUTO-REJECT (HARD FILTER):
    - Generic tutorials ("How to use ChatGPT", "5 tips for AI").
    - Financial fluff or stock market speculation ("AI stocks are rising").
    - Surface-level marketing PR ("Company X integrates AI into their sidebar").
    - Legacy news from 2024 or 2025.

    SCORING LOGIC (0-100):
    - 95-100: Critical paradigm shift (e.g., Llama 4 release, Sora public API, native audio-to-audio).
    - 80-94: Significant technical update or strategic pivot by a major ecosystem player.
    - <80: Do not return.

    Language: Hebrew.
  `;

  const userPrompt = `
    SCAN TARGETS:
    - Domains: ${filters.selectedDomains.join(", ")}
    - Subfields: ${filters.selectedSubfields.join(", ")}
    - Entities: ${filters.selectedCompanies.join(", ")}
    - Specific Topics: ${filters.selectedSubtopics.join(", ")}

    ${filters.isTrending ? "PRIORITY: Focus on rapid adoption and developer velocity." : ""}
    ${filters.isViral ? "PRIORITY: Focus on social hype and non-obvious breakthroughs." : ""}

    Provide 5-8 high-signal items in Hebrew.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: userPrompt,
      config: {
        systemInstruction: systemInstruction,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            items: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  title: { type: Type.STRING, description: "Raw news title" },
                  score: { type: Type.NUMBER, description: "Signal score 80-100" },
                  summary: { type: Type.STRING, description: "One sentence summary" },
                  link: { type: Type.STRING, description: "Source URL" }
                },
                required: ["title", "score", "summary", "link"]
              }
            }
          },
          required: ["items"]
        }
      }
    });

    const data = JSON.parse(response.text);
    return (data.items || []).map((item: any, idx: number) => ({
      ...item,
      id: item.id || `news-${Date.now()}-${idx}`
    }));
  } catch (error) {
    console.error("Discovery failed:", error);
    return [];
  }
};

/**
 * THE REFINING ENGINE (SUPER-MENTOR)
 */
export const refineCuratedContent = async (rawItem: any): Promise<RefinedItem> => {
  const model = "gemini-3-pro-preview";

  const systemInstruction = `
    You are the 'Super-Mentor Curator'. You rewrite technical signals into high-level strategy.
    Act as a fusion of Marty Cagan (Product Strategy), W. Chan Kim (Blue Ocean), and Paul Graham (Startup Value).

    MENTAL MODELS:
    1. Marty Cagan (Product): Focus on the 'Value Test' - will users choose to use this? Does it solve a real problem or just create a feature? Focus on Product Market Fit.
    2. W. Chan Kim (Blue Ocean): Focus on 'Eliminate/Create' - does this make competitors irrelevant? Does it create a new category of value?
    3. Paul Graham (YC): Focus on the 'Secret' - what non-obvious thing is happening here? Is there a technical 'unfair advantage'?

    WRITING STYLE (HEBREW):
    - Tone: Minimalist, elite, cold but visionary. No marketing superlatives.
    - Format: Use three specific headers in Hebrew: 'PREMIUM HOOK', 'THE 1% CASE', 'CURATOR VERDICT'.
    - Language: Professional High-Tech Hebrew. Mix English terms naturally (e.g., Inference, RAG, Zero-shot).

    FEW-SHOT EXAMPLES:

    ITEM: Groq LPU v2
    {
      "hook": "עידן ה-Zero Latency: התשתית של Groq הופכת את ה-Real-time לסטנדרט.",
      "justification": "המעבר ל-LPU Inference מאפשר מהירויות שמשנות את ה-UX מן היסוד. פול גרהם היה מזהה כאן 'Secret' טכנולוגי שיוצר יתרון לא הוגן.",
      "verdict": "מי שלא בונה על Latency נמוך ב-2026, בונה מוצר מת."
    }
  `;

  const userPrompt = `Refine this signal: ${JSON.stringify(rawItem)}`;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: userPrompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            hook: { type: Type.STRING },
            justification: { type: Type.STRING },
            verdict: { type: Type.STRING }
          },
          required: ["hook", "justification", "verdict"]
        }
      }
    });

    const refined = JSON.parse(response.text);
    return {
      ...refined,
      id: rawItem.id,
      originalLink: rawItem.link,
      originalTitle: rawItem.title
    };
  } catch (error) {
    console.error("Refinement failed:", error);
    throw error;
  }
};

